codeExercises.solution:
import exitHook from 'async-exit-hook';
import { CONNECT_DB, CLOSE_DB } from './db.js';

const START_SERVER = () => {
  console.log('Server starting...');
  console.log('Server is running! Press Ctrl+C to exit.');
};

// 1. Đăng ký hook
exitHook(async () => {
  console.log('Exit signal received. Closing DB connection...');
  await CLOSE_DB();
  console.log('Cleanup finished.');
});

// 2. Kết nối và khởi động server
CONNECT_DB()
  .then(() => {
    console.log('DB connection successful.');
    // 3. Nếu thành công
    START_SERVER();
  })
  .catch(error => {
    // 4. Nếu thất bại
    console.error('Failed to connect to DB:', error);
    process.exit(1);
  });
